// src/pages/Dashboard.js
import React, { useMemo } from 'react';
import Layout from '../components/Layout';
import StatCard from '../components/StatCard';
import SkillBar from '../components/SkillBar';
import GapCard from '../components/GapCard';
import ActivityGrid from '../components/ActivityGrid';
import { useSkills } from '../context/SkillsContext';
import { useNavigate } from 'react-router-dom';

// Default skills shown if user has none yet
const DEFAULT_SKILLS = [
  { name: 'React.js', level: 82 },
  { name: 'JavaScript', level: 75 },
  { name: 'CSS/Tailwind', level: 68 },
  { name: 'TypeScript', level: 20 },
  { name: 'Node.js', level: 45 },
];

const DEFAULT_GAPS = [
  { name: 'TypeScript', freq: 89, status: 'missing' },
  { name: 'Jest + RTL', freq: 64, status: 'beginner' },
  { name: 'System Design', freq: 58, status: null },
  { name: 'REST API design', freq: 51, status: 'learning' },
  { name: 'Docker basics', freq: 40, status: 'low priority' },
];

export default function Dashboard() {
  const { skills, analyses, activity, streak, avgLevel, criticalGaps } = useSkills();
  const navigate = useNavigate();

  // Use real data if available, otherwise fall back to defaults for a good demo
  const displaySkills = useMemo(() => {
    if (skills.length > 0) return skills.slice(0, 5);
    return DEFAULT_SKILLS;
  }, [skills]);

  const displayGaps = useMemo(() => {
    if (criticalGaps.length > 0) return criticalGaps;
    return DEFAULT_GAPS;
  }, [criticalGaps]);

  const readiness = avgLevel > 0 ? avgLevel : 68;
  const skillCount = skills.length > 0 ? skills.length : 14;
  const gapCount = displayGaps.length;
  const currentStreak = streak > 0 ? streak : 12;

  // Sync time label
  const syncLabel = 'synced 2m ago';

  return (
    <Layout>
      <div style={styles.page}>
        {/* Top bar */}
        <div style={styles.topbar}>
          <div>
            <div style={styles.filepath}>// overview.tsx</div>
            <div style={styles.pageTitle}>Command Center</div>
          </div>
          <div style={styles.liveChip}>
            <span style={styles.liveDot} />
            live · {syncLabel}
          </div>
        </div>

        {/* Stat row */}
        <div style={styles.statRow}>
          <StatCard
            label="READINESS"
            value={readiness}
            unit="%"
            sub="↑ 14% since Jan"
          />
          <StatCard
            label="SKILLS TRACKED"
            value={skillCount}
            unit=" skills"
            sub="↑ 2 this week"
          />
          <StatCard
            label="GAP COUNT"
            value={gapCount}
            unit=" crit"
            sub="resume analysed"
            subColor="#f85149"
          />
          <StatCard
            label="STREAK"
            value={currentStreak}
            unit=" days"
            sub="personal best"
            subColor="#8b949e"
          />
        </div>

        {/* Main content row */}
        <div style={styles.contentRow}>
          {/* Left — Gap Analysis */}
          <div style={styles.gapPanel}>
            <div style={styles.panelHeader}>
              <span style={styles.panelLabel}>GAP_ANALYSIS.JSON</span>
              <div style={styles.jdChip}>
                {gapCount} gaps · flipkart jd
              </div>
            </div>
            <div style={styles.gapList}>
              {displayGaps.map((gap, i) => (
                <GapCard
                  key={i}
                  name={gap.name}
                  freq={gap.freq}
                  status={gap.status}
                />
              ))}
            </div>
            <button
              style={styles.analyzeBtn}
              onClick={() => navigate('/analyze')}
            >
              + run new analysis
            </button>
          </div>

          {/* Right — Skill snapshot + Activity */}
          <div style={styles.rightCol}>
            {/* Skill snapshot */}
            <div style={styles.panel}>
              <div style={styles.panelHeader}>
                <span style={styles.panelLabel}>SKILL_SNAPSHOT[]</span>
                <span style={styles.avgChip}>avg {readiness}%</span>
              </div>
              <div style={{ marginTop: 16 }}>
                {displaySkills.map((s, i) => (
                  <SkillBar key={i} name={s.name} level={s.level} />
                ))}
              </div>
              <button
                style={styles.viewAllBtn}
                onClick={() => navigate('/skills')}
              >
                view all skills →
              </button>
            </div>

            {/* Activity grid */}
            <div style={styles.panel}>
              <ActivityGrid activity={activity} />
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
}

const styles = {
  page: {
    padding: 24,
    display: 'flex',
    flexDirection: 'column',
    gap: 20,
    animation: 'fadeIn 0.3s ease',
  },
  topbar: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'flex-end',
  },
  filepath: {
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 11,
    color: '#6e7681',
    marginBottom: 4,
  },
  pageTitle: {
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 22,
    fontWeight: 700,
    color: '#e6edf3',
  },
  liveChip: {
    display: 'flex',
    alignItems: 'center',
    gap: 6,
    background: '#1c2128',
    border: '1px solid #30363d',
    borderRadius: 20,
    padding: '6px 14px',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 11,
    color: '#8b949e',
  },
  liveDot: {
    width: 7,
    height: 7,
    borderRadius: '50%',
    background: '#3fb950',
    display: 'inline-block',
    animation: 'pulse-dot 2s infinite',
  },
  statRow: {
    display: 'flex',
    gap: 16,
  },
  contentRow: {
    display: 'flex',
    gap: 16,
    flex: 1,
  },
  gapPanel: {
    flex: 1,
    background: '#1c2128',
    border: '1px solid #30363d',
    borderRadius: 6,
    padding: 20,
    display: 'flex',
    flexDirection: 'column',
  },
  rightCol: {
    width: 280,
    display: 'flex',
    flexDirection: 'column',
    gap: 16,
  },
  panel: {
    background: '#1c2128',
    border: '1px solid #30363d',
    borderRadius: 6,
    padding: 16,
  },
  panelHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 4,
  },
  panelLabel: {
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 10,
    color: '#6e7681',
    letterSpacing: '0.08em',
  },
  jdChip: {
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 10,
    background: '#f8514922',
    color: '#f85149',
    border: '1px solid #f8514444',
    borderRadius: 4,
    padding: '3px 8px',
  },
  avgChip: {
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 10,
    color: '#6e7681',
  },
  gapList: {
    flex: 1,
    marginTop: 8,
  },
  analyzeBtn: {
    marginTop: 16,
    background: 'none',
    border: '1px dashed #30363d',
    borderRadius: 4,
    padding: '8px',
    color: '#8b949e',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 11,
    cursor: 'pointer',
    width: '100%',
  },
  viewAllBtn: {
    marginTop: 12,
    background: 'none',
    border: 'none',
    color: '#388bfd',
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 11,
    cursor: 'pointer',
    padding: 0,
  },
};
